const rawOutput = $input.first().json.output;

// Step 1: Extract the outer JSON array part (between first "[" and last "]")
const outerStart = rawOutput.indexOf('[');
const outerEnd = rawOutput.lastIndexOf(']') + 1;
const outerJsonText = rawOutput.slice(outerStart, outerEnd);

// Step 2: Parse outer JSON
let outerArray;
try {
  outerArray = JSON.parse(outerJsonText);
} catch (e) {
  throw new Error('❌ Failed to parse outer JSON: ' + e.message);
}

// Step 3: Clean the inner output string (may contain extra characters too)
const innerRaw = outerArray[0].output;

// Step 4: Extract only the valid array part from the inner JSON string
const innerStart = innerRaw.indexOf('[');
const innerEnd = innerRaw.lastIndexOf(']') + 1;
const innerJsonText = innerRaw.slice(innerStart, innerEnd);

// Step 5: Parse inner JSON safely
let parsedInner;
try {
  parsedInner = JSON.parse(innerJsonText);
} catch (e) {
  throw new Error('❌ Failed to parse inner output JSON: ' + e.message);
}

// Step 6: Return in n8n format
return parsedInner.map(item => ({
  json: item
}));
